'use client'
import { cn } from '@cascivo/core'
import type { HTMLAttributes, ReactNode } from 'react'
import styles from './data-list.module.css'

export interface DataListItem {
  id?: string
  label: ReactNode
  value: ReactNode
}

export interface DataListProps extends HTMLAttributes<HTMLDListElement> {
  items: DataListItem[]
  orientation?: 'horizontal' | 'vertical'
  dividers?: boolean
  size?: 'sm' | 'md'
}

export function DataList({
  items,
  orientation = 'horizontal',
  dividers = false,
  size = 'md',
  className,
  ...props
}: DataListProps) {
  return (
    <dl
      data-orientation={orientation}
      data-size={size}
      data-dividers={dividers ? '' : undefined}
      className={cn(styles['list'], className as string | undefined)}
      {...props}
    >
      {items.map((item, i) => (
        <div key={item.id ?? i} className={styles['row']}>
          <dt className={styles['term']}>{item.label}</dt>
          <dd className={styles['detail']}>{item.value}</dd>
        </div>
      ))}
    </dl>
  )
}

@layer cascivo.component {
  .list {
    margin: 0;
    font-family: var(--cascivo-font-sans);
    color: var(--cascivo-color-text);
    line-height: var(--cascivo-leading-normal);

    &[data-size='sm'] {
      font-size: var(--cascivo-text-xs);
      --_row-gap: var(--cascivo-space-2);
      --_pair-gap: var(--cascivo-space-2);
    }

    &[data-size='md'] {
      font-size: var(--cascivo-text-sm);
      --_row-gap: var(--cascivo-space-3);
      --_pair-gap: var(--cascivo-space-4);
    }
  }

  .row {
    display: grid;
    gap: var(--_pair-gap);
    padding-block: var(--_row-gap);
  }

  .list[data-orientation='horizontal'] .row {
    grid-template-columns: minmax(0, 1fr) minmax(0, 2fr);
    align-items: baseline;
  }

  .list[data-orientation='vertical'] .row {
    grid-template-columns: 1fr;
    gap: var(--cascivo-space-1);
  }

  .list[data-dividers] .row {
    border-block-end: 1px solid var(--cascivo-color-border);
  }

  .list[data-dividers] .row:last-child {
    border-block-end: none;
  }

  .term {
    margin: 0;
    color: var(--cascivo-color-text-subtle);
    font-weight: var(--cascivo-font-medium);
  }

  .detail {
    margin: 0;
    margin-inline-start: 0;
    color: var(--cascivo-color-text);
  }
}

@media (forced-colors: active) {
  .list[data-dividers] .row {
    border-block-end: 1px solid CanvasText;
  }
}
